# scripts/run-eval-regression.py
import json
import time
import sys
from pathlib import Path
from typing import Any
import anthropic
import yaml

SUITE_FILE = "eval/regression-suite.yaml"
MODEL = "claude-3-7-sonnet-20250219"

def load_suite() -> dict:
    return yaml.safe_load(Path(SUITE_FILE).read_text())

def grade_response(grading: dict, response_text: str, tool_calls: list) -> bool:
    """Grade a model response against the grading criteria."""
    gt = grading["type"]
    if gt == "contains_all":
        return all(v.lower() in response_text.lower() for v in grading["values"])
    elif gt == "refusal_check":
        refusal_indicators = ["i can't", "i cannot", "i'm unable", "i won't", "sorry"]
        has_refusal = any(r in response_text.lower() for r in refusal_indicators)
        return has_refusal == grading.get("must_refuse", False)
    elif gt == "tool_called":
        return any(tc.get("name") == grading["tool_name"] for tc in tool_calls)
    elif gt == "valid_json":
        try:
            parsed = json.loads(response_text)
            return all(k in parsed for k in grading.get("required_keys", []))
        except json.JSONDecodeError:
            return False
    elif gt == "pattern_absent":
        return grading["pattern"].lower() not in response_text.lower()
    return True

def run_suite(suite: dict) -> dict:
    """Run all test cases and return aggregated scores."""
    client = anthropic.Anthropic()
    results_by_category = {}

    for case in suite["cases"]:
        category = case["category"]
        if category not in results_by_category:
            results_by_category[category] = {"pass": 0, "fail": 0, "latencies": []}

        start = time.perf_counter()
        resp = client.messages.create(
            model=MODEL,
            max_tokens=512,
            messages=[{"role": "user", "content": case["input"]["content"]}],
        )
        latency_ms = (time.perf_counter() - start) * 1000

        response_text = resp.content[0].text if resp.content else ""
        tool_calls = [b.model_dump() for b in resp.content if b.type == "tool_use"]

        passed = grade_response(case["grading"], response_text, tool_calls)
        results_by_category[category]["pass" if passed else "fail"] += 1
        results_by_category[category]["latencies"].append(latency_ms)

    scores = {}
    for cat, data in results_by_category.items():
        total = data["pass"] + data["fail"]
        lats = sorted(data["latencies"])
        scores[cat] = {
            "accuracy": data["pass"] / total if total else 0,
            "p99_latency_ms": lats[int(len(lats) * 0.99)] if lats else 0,
        }
    return scores

def compare_scores(before: dict, after: dict, tolerances: dict) -> bool:
    """Compare before/after scores against tolerances. Returns True if safe."""
    all_pass = True
    print("\nEval Regression Comparison:")
    for metric, before_score in before.items():
        after_score = after.get(metric, {})
        b_acc = before_score.get("accuracy", 0)
        a_acc = after_score.get("accuracy", 0)
        delta = a_acc - b_acc
        tol = tolerances.get(metric, 0.01)
        status = "PASS" if delta >= -tol else "FAIL"
        print(f"  {metric}: {b_acc:.4f} → {a_acc:.4f} (Δ={delta:+.4f}) [{status}]")
        if status == "FAIL":
            all_pass = False
    return all_pass

if __name__ == "__main__":
    phase = sys.argv[1]  # "before" or "after" or "compare"
    suite = load_suite()

    if phase in ("before", "after"):
        scores = run_suite(suite)
        Path(f"eval-regression-{phase}.json").write_text(json.dumps(scores, indent=2))
        print(f"Saved {phase} scores")
    elif phase == "compare":
        before = json.loads(Path("eval-regression-before.json").read_text())
        after = json.loads(Path("eval-regression-after.json").read_text())
        safe = compare_scores(before, after, suite["tolerance"])
        sys.exit(0 if safe else 1)
